#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res;
}
inline void Swap(int &x,int &y){int tmp=x;x=y;y=tmp;}
const int N=2e5+10;int m;
struct Graph
{
	int head[N],des[N<<1],nxt[N<<1],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];head[x]=cnt;des[cnt]=y;}
}a;
int n,Rt[N],cnt;struct Seg{int l,r,sum;}t[N*40];
inline void build(int l,int r,int &cur)
{
	cur=++cnt;if(l==r)return;int mid=(l+r)>>1;
	if(l<=mid)build(l,mid,t[cur].l);if(r>mid)build(mid+1,r,t[cur].r);
}
inline void add(int &cur,int pos,int val,int l=1,int r=m)
{
	t[++cnt]=t[cur];t[cur=cnt].sum+=val;if(l==r)return;int mid=(l+r)>>1;
	(pos<=mid)?add(t[cur].l,pos,val,l,mid):add(t[cur].r,pos,val,mid+1,r);return;
}
inline int qry(int u,int v,int lca,int fca,int k,int l=1,int r=m)
{
	if(l==r)return l;int mid=(l+r)>>1,sum=0;
	sum=t[t[u].l].sum+t[t[v].l].sum-t[t[lca].l].sum-t[t[fca].l].sum;
	if(sum>=k)return qry(t[u].l,t[v].l,t[lca].l,t[fca].l,k,l,mid);
	return qry(t[u].r,t[v].r,t[lca].r,t[fca].r,k-sum,mid+1,r); 
}
int dep[N],siz[N],mxs[N],fa[N],top[N],col[N],P[N];
inline void dfs0(int u=1,int f=0)
{
	add(Rt[u]=Rt[f],col[u],1);
	dep[u]=dep[f]+1;siz[u]=1;fa[u]=f;
	grep(a,u,i)
	{
		int v=a.des[i];if(v==f)continue;dfs0(v,u);
		siz[u]+=siz[v];siz[v]>siz[mxs[u]]?siz[u]=siz[mxs[u]=v]:0;
	}
}
inline void dfs1(int u=1,int f=0,int tp=1)
{
	top[u]=tp;if(mxs[u])dfs1(mxs[u],u,tp);
	grep(a,u,i){int v=a.des[i];if(v^f&&v^mxs[u])dfs1(v,u,v);}
}
inline int LCA(int u,int v)
{
	while(top[u]^top[v]){if(dep[top[u]]<dep[top[v]])Swap(u,v);u=fa[top[u]];}
	return dep[u]<dep[v]?u:v;
}
int main()
{
	n=read();int q=read();rep(1,n,i)P[i]=col[i]=read();
	sort(P+1,P+n+1);m=unique(P+1,P+n+1)-P-1;
	rep(1,n,i){int l=1,r=m,res=1,mid;while(l<=r)P[mid=(l+r)>>1]<=col[i]?(l=mid+1,res=mid):(r=mid-1);col[i]=res;}
	rep(2,n,i){int x=read(),y=read();a.ins(x,y);a.ins(y,x);}
	build(1,n,Rt[0]);dfs0();dfs1();int lst=0;
	rep(1,q,i)
	{
		int u=read(),v=read(),k=read(),lca=LCA(u,v);
		printf("%d\n",lst=P[qry(Rt[u],Rt[v],Rt[lca],Rt[fa[lca]],k)]);
	}
}
